#include <bits/stdc++.h>
using namespace std;

struct Coin {
    int m, v;
    double p;
} coin[105];

bool cmp(Coin a, Coin b) {
    return a.p > b.p;
}

int main() {
    int n, t;
    double ans = 0;
    cin >> n >> t;
    for (int i = 0; i < n; i++) {
        cin >> coin[i].m >> coin[i].v;
        coin[i].p = double(coin[i].v) / coin[i].m;
    }
    sort(coin, coin + n, cmp);
    for (int i = 0; i < n; i++) {
        if (coin[i].m >= t) {
            ans += coin[i].p * t;
            break;
        }
        else {
            ans += coin[i].v;
            t -= coin[i].m;
        }
    }
    printf("%.2f", ans);
    return 0;
}
